mapper.select:
select book.id, book.book_name, book.author_id, book.publisher_id, book.cover_url, book.isbn, book.introduction, book.language, book.publish_date, book.price, book.number, author.author_name, publish.publisher_name from tb_book book join tb_author author on book.author_id = author.id join tb_publisher publish on book.publisher_id = publish.id where book.is_delete=0
and book.book_name like concat('%', #{bookPageDTO.bookName}, '%')
and book.isbn like concat('%', #{bookPageDTO.isbn}, '%')
and book.author_id = #{bookPageDTO.authorId}
and book.publisher_id = #{bookPageDTO.publisherId}
and book.language = #{bookPageDTO.language}
